/// Event processor for handling events from JSONL files
pub struct EventProcessor {
    /// Event handlers
    handlers: Vec<Box<dyn EventHandler>>,
    /// Whether to replay events
    replay_mode: bool,
}

impl EventProcessor {
    /// Create a new event processor
    pub fn new(replay_mode: bool) -> Self {
        Self {
            handlers: Vec::new(),
            replay_mode,
        }
    }

    /// Add an event handler
    pub fn add_handler(&mut self, handler: Box<dyn EventHandler>) {
        self.handlers.push(handler);
    }

    /// Process events from a JSONL file
    pub fn process_file(&mut self, file_path: &PathBuf) -> Result<()> {
        let content = std::fs::read_to_string(file_path).context(format!(
            "Failed to read event file: {}",
            file_path.display()
        ))?;

        let mut events = Vec::new();
        for line in content.lines() {
            if !line.trim().is_empty() {
                if let Ok(event) = serde_json::from_str::<HooksmithEvent>(line) {
                    events.push(event);
                }
            }
        }

        println!(
            "📊 Processing {} events from {}",
            events.len(),
            file_path.display()
        );

        for event in events {
            for handler in &mut self.handlers {
                if handler.should_handle(&event) {
                    if let Err(e) = handler.handle_event(&event) {
                        eprintln!("Handler {} failed: {}", handler.name(), e);
                    }
                }
            }
        }

        Ok(())
    }

    /// Start processing events from the global event bus
    pub async fn start_processing(&mut self) -> Result<()> {
        let mut receiver = if let Some(bus) = get_event_bus() {
            bus.subscribe()
        } else {
            anyhow::bail!("Event bus not initialized");
        };

        println!("🎯 Event processor started");

        while let Ok(event) = receiver.recv().await {
            for handler in &mut self.handlers {
                if handler.should_handle(&event) {
                    if let Err(e) = handler.handle_event(&event) {
                        eprintln!("Handler {} failed: {}", handler.name(), e);
                    }
                }
            }
        }

        Ok(())
    }
}

