/// Auto-push handler
pub struct AutoPushHandler {
    /// Whether auto-push is enabled
    enabled: bool,
    /// Current validation state
    validation_passed: bool,
}

impl AutoPushHandler {
    pub fn new(enabled: bool) -> Self {
        Self {
            enabled,
            validation_passed: false,
        }
    }
}

impl EventHandler for AutoPushHandler {
    fn handle_event(&mut self, event: &HooksmithEvent) -> Result<()> {
        if !self.enabled {
            return Ok(());
        }

        match event.event.as_str() {
            "validation_passed" => {
                self.validation_passed = true;
                println!("✅ Auto-push: Validation passed, ready for commit");
            }
            "validation_failed" => {
                self.validation_passed = false;
                println!("❌ Auto-push: Validation failed, commit blocked");
            }
            "commit_created" => {
                if self.validation_passed {
                    println!("🚀 Auto-push: Commit created, attempting push");
                    // Here you would trigger the actual git push
                    emit_push_event("auto-push-handler", true, "main", "origin", None)?;
                } else {
                    println!("⚠️ Auto-push: Commit created but validation failed, skipping push");
                }
            }
            _ => {}
        }

        Ok(())
    }

    fn name(&self) -> &str {
        "auto_push"
    }

    fn should_handle(&self, event: &HooksmithEvent) -> bool {
        matches!(
            event.event.as_str(),
            "validation_passed" | "validation_failed" | "commit_created"
        )
    }
}

