/// Metrics handler
pub struct MetricsHandler {
    /// Performance metrics
    metrics: HashMap<String, u64>,
}

impl MetricsHandler {
    pub fn new() -> Self {
        Self {
            metrics: HashMap::new(),
        }
    }
}

impl EventHandler for MetricsHandler {
    fn handle_event(&mut self, event: &HooksmithEvent) -> Result<()> {
        // Track event counts
        *self
            .metrics
            .entry(format!("events.{}", event.event))
            .or_insert(0) += 1;

        // Track performance
        if let Some(duration) = event.duration_ms {
            let key = format!("duration.{}", event.event);
            let current = self.metrics.get(&key).unwrap_or(&0);
            self.metrics.insert(key, current + duration);
        }

        Ok(())
    }

    fn name(&self) -> &str {
        "metrics"
    }

    fn should_handle(&self, _event: &HooksmithEvent) -> bool {
        true // Track all events
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_event_creation() {
        let context = serde_json::json!({
            "branch": "main",
            "files": ["src/main.rs"]
        });

        let event = HooksmithEvent::new(
            "xtask-auto-push".to_string(),
            "validation_passed".to_string(),
            context,
        );

        assert_eq!(event.actor, "xtask-auto-push");
        assert_eq!(event.event, "validation_passed");
        assert!(event.id.len() > 0);
    }

    #[test]
    fn test_event_with_hook_and_state() {
        let context = serde_json::json!({});
        let event = HooksmithEvent::new(
            "lefthook".to_string(),
            "validation_started".to_string(),
            context,
        )
        .with_hook("pre-commit".to_string())
        .with_state("validating".to_string());

        assert_eq!(event.hook, Some("pre-commit".to_string()));
        assert_eq!(event.state, Some("validating".to_string()));
    }

    #[test]
    fn test_event_jsonl_serialization() {
        let context = serde_json::json!({
            "branch": "feature/foo"
        });

        let event = HooksmithEvent::new(
            "xtask-auto-push".to_string(),
            "commit_created".to_string(),
            context,
        );

        let jsonl = event.to_jsonl().unwrap();
        assert!(jsonl.contains("commit_created"));
        assert!(jsonl.contains("feature/foo"));
    }
}
